
import Status from "@/app/components/admin components/Status";
import { Pencil, Trash2, Plus, Delete } from "lucide-react";
import React from "react";
import { fetchapi } from "@/api_call/api";
import Link from "next/link";
import DeleteBtn from "@/app/components/admin components/DeleteBtn";

export default async function UserManagementTable() {

  const categories = await fetchapi()
  console.log(categories)
  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-semibold text-gray-800">
            Product Categories
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            Manage your product categories
          </p>
        </div>

        <Link href={"category/addCategory"}>
        <button className="flex items-center gap-2 px-5 py-2.5 bg-orange-500 text-white rounded-xl shadow hover:shadow-md hover:scale-105 transition">
          <Plus size={18} />
          Add Category
        </button>
        </Link>
      
      </div>
  
      {/* Table Container */}
      <div className="bg-white rounded-2xl shadow-sm border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full text-left">
            {/* Table Head */}
            <thead className="bg-gray-100 border-b">
              <tr>
                <th className="px-6 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Image
                </th>
                <th className="px-6 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Category Name
                </th>
                <th className="px-6 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Slug
                </th>
                  <Status/>
                <th className="px-6 py-4 text-sm font-semibold text-gray-600 uppercase tracking-wide">
                  Actions
                </th>
              </tr>
            </thead>
  
            {/* Table Body */}
            <tbody>
              {categories.map((user, index) => (
                <tr
                  key={index}
                  className="border-b hover:bg-gray-50 transition"
                >
                  {/* Image */}
                  <td className="px-6 py-4">
                    <img
                      src={user.image}
                      alt={user.name}
                      className="w-12 h-12 rounded-lg object-cover border"
                    />
                  </td>
  
                  {/* Name */}
                  <td className="px-6 py-4 font-medium text-gray-800">
                    {user.name}
                  </td>
  
                  {/* Slug */}
                  <td className="px-6 py-4 text-gray-500">
                    {user.slug}
                  </td>
  
                  {/* Status */}
                  <Status status={user.status} id={user._id} />
  
                  {/* Actions */}
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                      <button className="p-2 rounded-lg hover:bg-blue-50 text-blue-600 hover:text-blue-800 transition">
                        <Pencil size={18} />
                      </button>

                      <DeleteBtn id={user._id}/>
                      
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
